import React from "react";
import type { IKitsInputText } from "@lmb-it/kitsconcerto-types";
import KitsContainer from "../../Helpers/FormContainer";
import { applyKeyFilterKeepPrev } from "../../Helpers/native/keyfilter";
import { FloatLabelNative } from "../../Helpers/native/FloatLabel";
import { Input, InputField, InputSlot, style } from "@lmb-it/kitsconcertomobile";
import { View } from "react-native";
import Addons from "../../Helpers/Addons";
import {useComponentDefaults, useFocusStyles} from "@lmb-it/kitsconcerto/Hooks";
import {useFormFieldKeyboardNav} from "../../../../../Hooks/useFormFieldKeyboardNav";
import {mergeRefs} from "../../../../../Utils/mergeRefs";

const KitsInputText = ({ ref, ...rawProps }: IKitsInputText) => {
    const {mergedProps: props, themeStyle} = useComponentDefaults('InputText', rawProps, 'Input');
    const {
        id,
        label,
        rightAddon,
        leftAddon,
        errors,
        invalid,
        hideError,
        required,
        keyFilter,
        value,
        defaultValue,
        attached,
        onChange,
        disabled,
        helperText,
        isFloatedLabel,
        placeholder,
        containerStyle,
        localProps,
        keyboardNavId,
        ...rest
    } = props;

    const {inputRef, navProps} = useFormFieldKeyboardNav(keyboardNavId ?? id);

    /** 🔑 controlled detection */
    const isControlled = value !== undefined;

    /** 🔹 internal state only for uncontrolled */
    const [internalValue, setInternalValue] = React.useState<string>(
        String(defaultValue ?? "")
    );

    /** 🔹 focused state (for FloatLabel + _focus styles) */
    const [isFocused, setFocused] = React.useState(false);
    const focusResolvedStyle = useFocusStyles(themeStyle, isFocused);

    /** 🔄 sync only when controlled */
    React.useEffect(() => {
        if (isControlled) {
            setInternalValue(String(value ?? ""));
        }
    }, [isControlled, value]);

    /** ✍️ change handler */
    const handleChangeText = (nextRaw: string) => {
        const prev = isControlled ? String(value ?? "") : internalValue;

        const filtered = keyFilter
            ? applyKeyFilterKeepPrev(prev, nextRaw, keyFilter as any)
            : nextRaw;

        if (!isControlled) {
            setInternalValue(filtered);
        }

        onChange?.({
            target: { value: filtered },
        } as any);
    };

    const displayValue = isControlled
        ? String(value ?? "")
        : internalValue;

    const inputEl = (
        <Input
            {...(localProps as any)}
            isDisabled={!!disabled}
            isInvalid={!!invalid}
            style={{width:'100%', ...focusResolvedStyle}}
            {...(rest as any)}
        >
            <InputField
                ref={mergeRefs(inputRef, ref)}
                value={displayValue}
                placeholder={isFloatedLabel ? undefined : placeholder}
                editable={!disabled}
                onChangeText={handleChangeText}
                onFocus={(e: any) => {
                    setFocused(true);
                    (rest as any)?.onFocus?.(e);
                }}
                onBlur={(e: any) => {
                    setFocused(false);
                    (rest as any)?.onBlur?.(e);
                }}
                {...navProps}
            />
        </Input>
    );

    if(attached){
        const attachedEl = (leftAddon || rightAddon) ? (
            <Addons leftAddon={leftAddon} rightAddon={rightAddon} invalid={!!invalid}>
                {inputEl}
            </Addons>
        ) : inputEl;

        return isFloatedLabel ? (
            <FloatLabelNative
                label={
                    typeof label === "string"
                        ? label
                        : (label as any)?.text ?? ""
                }
                value={displayValue}
                isFocused={isFocused}
                disabled={disabled}
                onFocusRequest={() => setFocused(true)}
            >
                <View style={{ width: "100%" }}>
                    {attachedEl}
                </View>
            </FloatLabelNative>
        ) : (
            attachedEl
        )
    }

    return (
        <KitsContainer
            id={id}
            disabled={disabled}
            hideError={hideError}
            isFloatedLabel={isFloatedLabel}
            helperText={helperText}
            rightAddon={rightAddon}
            leftAddon={leftAddon}
            required={required}
            errors={errors}
            invalid={invalid}
            label={label}
            containerStyle={containerStyle}
        >
            {isFloatedLabel ? (
                <FloatLabelNative
                    label={
                        typeof label === "string"
                            ? label
                            : (label as any)?.text ?? ""
                    }
                    value={displayValue}
                    isFocused={isFocused}
                    disabled={disabled}
                    onFocusRequest={() => setFocused(true)}
                >
                    <View style={{ width: "100%" }}>
                        {inputEl}
                    </View>
                </FloatLabelNative>
            ) : (
                inputEl
            )}
        </KitsContainer>
    );
};

export default KitsInputText;
